class PaymentService {
  static final PaymentService _instance = PaymentService._internal();
  factory PaymentService() => _instance;
  PaymentService._internal();

  final InAppPurchase _inAppPurchase = InAppPurchase.instance;
  bool _iapAvailable = false;

  Future<void> initialize() async {
    final bool isAvailable = await _inAppPurchase.isAvailable();
    _iapAvailable = isAvailable;
  }

  Stream<List<PurchaseDetails>> listenToPurchases() {
    return _inAppPurchase.purchaseStream;
  }

  Future<void> buyConsumable({required String productId}) async {
    if (!_iapAvailable) return;
    final ProductDetailsResponse response = await _inAppPurchase.queryProductDetails({productId});
    if (response.notFoundIDs.isNotEmpty) return;
    final ProductDetails productDetails = response.productDetails.first;
    final PurchaseParam purchaseParam = PurchaseParam(productDetails: productDetails);
    await _inAppPurchase.buyConsumable(purchaseParam: purchaseParam);
  }

  Future<void> consumePurchase(PurchaseDetails purchaseDetails) async {
    if (purchaseDetails.status == PurchaseStatus.purchased) {
      await _inAppPurchase.completePurchase(purchaseDetails);
    }
  }

  Future<void> refundPurchase(String orderId) async {
    // Implement secure refund mechanism with payment gateway
  }
}

