class _PaymentScreenState extends State<PaymentScreen> {
  final PaymentService _paymentService = PaymentService();
  final MobileWalletService _mobileWalletService = MobileWalletService();
  final PaymentGateway _paymentGateway = PaymentGateway(
    "https://example.com",
    "YOUR_SECURE_KEY",
  );
  bool _isLoading = false;

  @override
  void initState() {
    super.initState();
    _initPaymentModule();
    _listenToPurchases();
  }

  Future<void> _initPaymentModule() async {
    await _paymentService.initialize();
    _mobileWalletService.addItem(label: "Product A", amount: "4.99");
    setState(() {});
  }

  void _listenToPurchases() {
    _paymentService.listenToPurchases().listen((purchaseDetailsList) {
      for (final purchase in purchaseDetailsList) {
        if (purchase.status == PurchaseStatus.purchased) {
          _paymentService.consumePurchase(purchase);
        }
      }
    });
  }

  Future<void> _buyProduct(String productId) async {
    setState(() => _isLoading = true);
    await _paymentService.buyConsumable(productId: productId);
    setState(() => _isLoading = false);
  }

  Future<void> _payWithGoogle() async {
    setState(() => _isLoading = true);
    final tokenizationKey = "GOOGLE_PAY_TOKENIZATION_KEY";
    await _mobileWalletService.processGooglePayPayment(tokenizationKey);
    // Access the payment method token here and send to server
    await _paymentGateway.processTransaction(
      amount: 4.99,
      paymentMethodToken: tokenizationKey,
    );
    setState(() => _isLoading = false);
  }

  Future<void> _payWithApple() async {
    setState(() => _isLoading = true);
    final tokenizationKey = "APPLE_PAY_TOKENIZATION_KEY";
    await _mobileWalletService.processApplePayPayment(tokenizationKey);
    // Access the payment method token here and send to server
    await _paymentGateway.processTransaction(
      amount: 4.99,
      paymentMethodToken: tokenizationKey,
    );
    setState(() => _isLoading = false);
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(title: const Text("Payment Module")),
      body: Center(
        child: _isLoading
            ? const CircularProgressIndicator()
            : Column(
                mainAxisAlignment: MainAxisAlignment.center,
                children: [
                  ElevatedButton(
                    onPressed: () => _buyProduct("product_id"),
                    child: const Text("Buy Product (In-App)"),
                  ),
                  const SizedBox(height: 16),
                  ElevatedButton(
                    onPressed: _payWithGoogle,
                    child: const Text("Pay with Google Pay"),
                  ),
                  const SizedBox(height: 16),
